MANIFEST_FILE = DATA_DIR / "manifest.json"


def enrich_badges(rows: list[dict]) -> list[dict]:
    rng = random.Random(SEED)
    enriched = []
    for idx, row in enumerate(rows, 1):
        item = dict(row)
        item.setdefault("badge_id", f"bdg_{idx:04d}")
        item.setdefault("scan_score", rng.choice([42, 58, 63, 71, 78, 84, 91]))
        item.setdefault("source", "badge_scan")
        item.setdefault(
            "session_interest", rng.choice(["AI operations", "field robotics", "camera QA", "partner follow-up"])
        )
        enriched.append(item)
    return enriched


