def build_manifest(data: dict) -> dict:
    endpoints = [
        "/health",
        "/api/events",
        "/api/events/{event_id}",
        "/api/events/{event_id}/orders",
        "/api/events/{event_id}/badges",
        "/api/events/{event_id}/sponsor_packages",
        "/api/finance/invoices?event_id=<event_id>",
        "/api/crm/accounts",
        "/api/crm/contacts",
        "/api/crm/opportunities",
        "/api/crm/campaign_members?event_id=<event_id>",
        "/api/tradeshows",
        "/api/tradeshows/{show_id}/exhibitors",
        "/api/tradeshows/{show_id}/meeting_interest",
        "/api/import_batches",
        "/api/import_batches/{batch_id}/raw_contacts",
        "/api/import_batches/{batch_id}/suppression",
        "/api/policies",
    ]
    list_counts = {key: len(value) for key, value in data.items() if isinstance(value, list)}
    return {
        "seed": SEED,
        "generated_at": GENERATED_AT,
        "generated_files": ["env/data/harborcrm_data.json", "env/data/manifest.json"],
        "public_endpoints": endpoints,
        "event_ids": [item["event_id"] for item in data["events"]],
        "show_ids": [item["show_id"] for item in data["tradeshows"]],
        "import_batch_ids": [item["batch_id"] for item in data["import_batches"]],
        "counts": list_counts,
        "construction_index": {
            "event_reconciliation_events": [
                "neuralops_2026",
                "edgeai_field_2026",
                "predictive_ops_2027",
                "industrial_vision_2027",
            ],
            "prospecting_shows": [
                "marinesense_2026",
                "aquafarm_robotics_2026",
                "nordic_aqua_2027",
                "bluetech_demo_2027",
            ],
            "contact_hygiene_batches": ["fall_webinar_import", "q1_partner_import"],
            "source_priority": data["policies"]["contact_hygiene"]["source_priority"],
            "platform_enums": data["policies"]["prospecting"]["platform_enums"],
        },
    }


def main() -> None:
    random.seed(SEED)
    DATA_DIR.mkdir(parents=True, exist_ok=True)
    data = build_data()
    manifest = build_manifest(data)
    DATA_FILE.write_text(json.dumps(data, indent=2, sort_keys=True) + "\n", encoding="utf-8")
    MANIFEST_FILE.write_text(json.dumps(manifest, indent=2, sort_keys=True) + "\n", encoding="utf-8")
    print(f"Wrote {DATA_FILE}")
    print(f"Wrote {MANIFEST_FILE}")


if __name__ == "__main__":
    main()
